const SetValue = async (context) => {
    const table = context?.Form?.CustomerInformationPage?.AuditMeasures || [];

    const combined = table
        .map(row => {
            const measure = row?.Measures?.Text;
            const cost = parseFloat(row?.MeasureCost_c?.Value);
            if (measure && !isNaN(cost)) {
                return `${measure}: $${cost.toFixed(2)}`;
            }
            return measure; // Return just measure if no valid cost
        })
        .filter(note => note);

    return combined.join(" \n");
